import './App.css';
import { Header } from './components/home/header/Header';
import {
  BrowserRouter as Router,
  Switch,
  Route,
  Link
} from "react-router-dom";
import { HomePage } from './components/pageComponent/HomePage';

function App() {
  return (
    <>
    <Router>
    <Header />
    <Switch>
      <Route path= '/' exact component={HomePage} />
    </Switch>
    </Router>
    </>
  );
}

export default App;
